/**
 * Webhook notification handler — dispatches HTTP webhook callbacks
 * for order lifecycle events.
 *
 * Integrates with the existing notification architecture via the EventBus.
 * External consumers register webhook URLs for specific event types,
 * and this handler fires HTTP POST requests when those events occur.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { AppEvent, EventType, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: WebhookPayload;
  success: boolean;
  deliveredAt: Date;
}

export interface WebhookPayload {
  event: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

export type WebhookSender = (url: string, payload: WebhookPayload) => Promise<boolean>;

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `wh-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `whd-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

/**
 * Default sender that performs an HTTP POST.
 * In tests, this is replaced with a mock sender.
 */
const defaultSender: WebhookSender = async (url: string, payload: WebhookPayload): Promise<boolean> => {
  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    return response.ok;
  } catch {
    return false;
  }
};

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: Map<string, WebhookRegistration> = new Map();
  private deliveries: WebhookDelivery[] = [];
  private sender: WebhookSender;

  constructor(private eventBus: EventBus, sender?: WebhookSender) {
    this.sender = sender ?? defaultSender;
    this.registerHandlers();
  }

  /**
   * Register event handlers for webhook dispatch.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleEvent(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleEvent(event);
    });
  }

  /**
   * Handle an event by dispatching to all registered webhooks for that event type.
   */
  private async handleEvent(event: AppEvent): Promise<void> {
    const webhooks = this.getRegistrationsForEvent(event.type);
    if (webhooks.length === 0) {
      return;
    }

    const payload = this.buildPayload(event);

    for (const webhook of webhooks) {
      this.logger.info(`Dispatching webhook ${webhook.id} to ${webhook.url} for ${event.type}`);
      const success = await this.sender(webhook.url, payload);

      const delivery: WebhookDelivery = {
        id: generateDeliveryId(),
        webhookId: webhook.id,
        url: webhook.url,
        eventType: event.type,
        payload,
        success,
        deliveredAt: new Date(),
      };
      this.deliveries.push(delivery);

      if (success) {
        this.logger.info(`Webhook ${webhook.id} delivered successfully`);
      } else {
        this.logger.warn(`Webhook ${webhook.id} delivery failed`);
      }
    }
  }

  /**
   * Build a webhook payload from an event.
   */
  private buildPayload(event: AppEvent): WebhookPayload {
    switch (event.type) {
      case 'order:created':
        return {
          event: event.type,
          timestamp: event.timestamp.toISOString(),
          data: {
            orderId: event.order.id,
            userId: event.user.id,
            items: event.order.items,
            total: event.order.total,
            status: event.order.status,
          },
        };
      case 'order:status-changed':
        return {
          event: event.type,
          timestamp: event.timestamp.toISOString(),
          data: {
            orderId: event.order.id,
            userId: event.order.userId,
            previousStatus: event.previousStatus,
            newStatus: event.newStatus,
          },
        };
    }
  }

  /**
   * Register a webhook URL for a specific event type.
   */
  register(url: string, eventType: EventType): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      createdAt: new Date(),
    };
    this.registrations.set(registration.id, registration);
    this.logger.info(`Webhook registered: ${registration.id} -> ${url} for ${eventType}`);
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregister(id: string): boolean {
    const deleted = this.registrations.delete(id);
    if (deleted) {
      this.logger.info(`Webhook unregistered: ${id}`);
    }
    return deleted;
  }

  /**
   * Get all webhook registrations.
   */
  getRegistrations(): WebhookRegistration[] {
    return Array.from(this.registrations.values());
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.getRegistrations().filter((r) => r.eventType === eventType);
  }

  /**
   * Get all webhook deliveries.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clear(): void {
    this.registrations.clear();
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookHandler,
  resetWebhookIdCounters,
} from '../../src/notifications/webhook.handler.js';
import type { WebhookPayload } from '../../src/notifications/webhook.handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let handler: WebhookHandler;
  let sentPayloads: Array<{ url: string; payload: WebhookPayload }>;
  let senderShouldSucceed: boolean;

  beforeEach(() => {
    eventBus = new EventBus();
    sentPayloads = [];
    senderShouldSucceed = true;
    resetWebhookIdCounters();

    const mockSender = async (url: string, payload: WebhookPayload): Promise<boolean> => {
      sentPayloads.push({ url, payload });
      return senderShouldSucceed;
    };

    handler = new WebhookHandler(eventBus, mockSender);
  });

  describe('webhook registration', () => {
    it('should register a webhook and return registration', () => {
      const reg = handler.register('https://example.com/hook', 'order:created');

      expect(reg.id).toBe('wh-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should assign sequential IDs', () => {
      const reg1 = handler.register('https://a.com/hook', 'order:created');
      const reg2 = handler.register('https://b.com/hook', 'order:status-changed');

      expect(reg1.id).toBe('wh-0001');
      expect(reg2.id).toBe('wh-0002');
    });

    it('should list all registrations', () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:status-changed');
      handler.register('https://c.com/hook', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook', () => {
      const reg = handler.register('https://a.com/hook', 'order:created');

      expect(handler.unregister(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering non-existent webhook', () => {
      expect(handler.unregister('wh-9999')).toBe(false);
    });
  });

  describe('order:created webhook dispatch', () => {
    const orderCreatedEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date('2026-01-01T00:00:00Z'),
    };

    it('should dispatch webhook on order created', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(orderCreatedEvent);

      expect(sentPayloads).toHaveLength(1);
      expect(sentPayloads[0]?.url).toBe('https://example.com/hook');
      expect(sentPayloads[0]?.payload.event).toBe('order:created');
      expect(sentPayloads[0]?.payload.data['orderId']).toBe('order-1');
      expect(sentPayloads[0]?.payload.data['userId']).toBe('user-1');
      expect(sentPayloads[0]?.payload.data['total']).toBe(20);
    });

    it('should include items in payload', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(orderCreatedEvent);

      const items = sentPayloads[0]?.payload.data['items'] as Array<Record<string, unknown>>;
      expect(items).toHaveLength(1);
      expect(items[0]?.['name']).toBe('Widget');
    });

    it('should dispatch to multiple webhooks', async () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      await eventBus.emit(orderCreatedEvent);

      expect(sentPayloads).toHaveLength(2);
      expect(sentPayloads[0]?.url).toBe('https://a.com/hook');
      expect(sentPayloads[1]?.url).toBe('https://b.com/hook');
    });

    it('should not dispatch to webhooks registered for different event', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(orderCreatedEvent);

      expect(sentPayloads).toHaveLength(0);
    });

    it('should not dispatch when no webhooks registered', async () => {
      await eventBus.emit(orderCreatedEvent);

      expect(sentPayloads).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('order:status-changed webhook dispatch', () => {
    const statusChangedEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date('2026-01-01T00:00:00Z'),
    };

    it('should dispatch webhook on status change', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(statusChangedEvent);

      expect(sentPayloads).toHaveLength(1);
      expect(sentPayloads[0]?.payload.event).toBe('order:status-changed');
      expect(sentPayloads[0]?.payload.data['orderId']).toBe('order-1');
      expect(sentPayloads[0]?.payload.data['previousStatus']).toBe('pending');
      expect(sentPayloads[0]?.payload.data['newStatus']).toBe('confirmed');
    });

    it('should include timestamp in payload', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(statusChangedEvent);

      expect(sentPayloads[0]?.payload.timestamp).toBe('2026-01-01T00:00:00.000Z');
    });
  });

  describe('delivery tracking', () => {
    it('should record successful deliveries', async () => {
      const reg = handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.id).toBe('whd-0001');
      expect(deliveries[0]?.webhookId).toBe(reg.id);
      expect(deliveries[0]?.success).toBe(true);
    });

    it('should record failed deliveries', async () => {
      senderShouldSucceed = false;
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(handler.getDeliveriesForWebhook(reg1.id)).toHaveLength(1);
      expect(handler.getDeliveryCount()).toBe(2);
    });
  });

  describe('clear', () => {
    it('should clear registrations and deliveries', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      handler.clear();
      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('integration with other handlers', () => {
    it('should work alongside NotificationService on same EventBus', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();
      const notificationService = new NotificationService(eventBus);

      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getDeliveryCount()).toBe(1);
      expect(notificationService.getNotificationCount()).toBe(1);
    });
  });
});

